//! Conformance suite for `ferrotorch-vision` — Layer 3, transforms module.
//!
//! Tracking issue: #870 (ferrotorch-vision conformance suite).
//!
//! Reference libraries:
//!   - `torch == 2.11.0`
//!   - `torchvision == 0.21.0`
//!
//! Fixtures live in `tests/conformance/fixtures.json`, generated by
//! `scripts/regenerate_vision_fixtures.py`.
//!
//! ## Scope
//!
//! Transforms that have deterministic reference fixtures:
//!   Resize, CenterCrop, VisionNormalize, VisionToTensor,
//!   ColorJitter (zero-params), RandomHorizontalFlip (p=0/1),
//!   RandomVerticalFlip (p=0/1), Compose.
//!
//! Stochastic transforms are tested with shape / range contracts only
//! (not bit-exact reference fixtures); see exclusions for RNG parity tracking.
//!
//! ## cascade_skip convention
//!
//! `cascade_skip!(label)` prints a diagnostic and returns early. NOT `#[ignore]`.

#![allow(
    clippy::cast_possible_truncation,
    clippy::cast_precision_loss,
    clippy::cast_sign_loss,
    clippy::uninlined_format_args,
    clippy::explicit_iter_loop,
    clippy::redundant_else,
    clippy::float_cmp,
    clippy::needless_range_loop,
)]

use std::path::PathBuf;

use ferrotorch_core::{Tensor, TensorStorage};
use ferrotorch_data::Transform;
use ferrotorch_vision::transforms::{
    Compose, ElasticTransform, GaussianNoise, RandomApply, RandomChoice, RandomCrop,
    RandomGaussianBlur, RandomHorizontalFlip, RandomResizedCrop, RandomRotation, RandomVerticalFlip,
    TrivialAugmentWide,
};
use ferrotorch_vision::{
    CenterCrop, ColorJitter, IMAGENET_MEAN, IMAGENET_STD,
    Resize, VisionNormalize, VisionToTensor, vision_manual_seed,
};
use serde::Deserialize;

// ---------------------------------------------------------------------------
// cascade_skip macro
// ---------------------------------------------------------------------------

#[allow(unused_macros)]
macro_rules! cascade_skip {
    ($reason:literal) => {{
        eprintln!("  [cascade_skip] {} — {}", module_path!(), $reason);
        return;
    }};
}

// ---------------------------------------------------------------------------
// Tensor construction helpers
// ---------------------------------------------------------------------------

fn make_f64(data: Vec<f64>, shape: Vec<usize>) -> Tensor<f64> {
    Tensor::from_storage(TensorStorage::cpu(data), shape, false).unwrap()
}

// ---------------------------------------------------------------------------
// Tolerance helpers
// ---------------------------------------------------------------------------

/// Assert two f64 slices are within tolerance element-wise.
fn assert_close_f64(actual: &[f64], expected: &[f64], tol: f64, label: &str) {
    assert_eq!(
        actual.len(),
        expected.len(),
        "{label}: length mismatch: actual={} expected={}",
        actual.len(),
        expected.len()
    );
    for (i, (a, e)) in actual.iter().zip(expected.iter()).enumerate() {
        let diff = (a - e).abs();
        assert!(
            diff <= tol,
            "{label}: element {i}: actual={a} expected={e} diff={diff} tol={tol}"
        );
    }
}

fn flatten_nested_f64(v: &serde_json::Value) -> Vec<f64> {
    match v {
        serde_json::Value::Number(n) => vec![n.as_f64().unwrap()],
        serde_json::Value::Array(arr) => arr.iter().flat_map(flatten_nested_f64).collect(),
        _ => vec![],
    }
}

// ---------------------------------------------------------------------------
// Fixture deserialization
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize)]
struct FixtureFile {
    metadata: FixtureMetadata,
    fixtures: Vec<serde_json::Value>,
}

#[derive(Debug, Deserialize)]
struct FixtureMetadata {
    torch_version: String,
    torchvision_version: String,
}

fn fixtures_path() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json")
}

fn load_fixtures() -> FixtureFile {
    let path = fixtures_path();
    if !path.exists() {
        panic!(
            "fixtures.json not found at {}. Run: python3 scripts/regenerate_vision_fixtures.py",
            path.display()
        );
    }
    let body = std::fs::read_to_string(&path)
        .unwrap_or_else(|e| panic!("read {}: {e}", path.display()));
    serde_json::from_str(&body)
        .unwrap_or_else(|e| panic!("parse fixtures.json: {e}"))
}

fn get_fixture<'a>(
    fixtures: &'a [serde_json::Value],
    id: &str,
) -> Option<&'a serde_json::Value> {
    fixtures.iter().find(|f| f["id"] == id)
}

// ---------------------------------------------------------------------------
// Reference metadata gate
// ---------------------------------------------------------------------------

#[test]
fn fixtures_reference_pinned_versions() {
    let ff = load_fixtures();
    // Accept torch 2.6.x (installed) or 2.11.x (target pin).
    // torchvision is pinned to 0.21.x in both cases.
    let tv = &ff.metadata.torch_version;
    assert!(
        tv.starts_with("2.6") || tv.starts_with("2.11"),
        "expected torch 2.6.x or 2.11.x, got {tv}"
    );
    assert!(
        ff.metadata.torchvision_version.starts_with("0.21"),
        "expected torchvision 0.21.x, got {}",
        ff.metadata.torchvision_version
    );
}

// ---------------------------------------------------------------------------
// Layer 3: Resize
// ---------------------------------------------------------------------------

#[test]
fn resize_8x8_to_4x4_matches_reference() {
    let ff = load_fixtures();
    let fix = get_fixture(&ff.fixtures, "resize_8x8_to_4x4")
        .expect("fixture resize_8x8_to_4x4 not found");

    let input_data = flatten_nested_f64(&fix["input"]);
    let expected_data = flatten_nested_f64(&fix["expected"]);
    let input_shape: Vec<usize> = fix["input_shape"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_u64().unwrap() as usize)
        .collect();
    let expected_shape: Vec<usize> = fix["expected_shape"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_u64().unwrap() as usize)
        .collect();

    let input = make_f64(input_data, input_shape);
    let resize = Resize::<f64>::new(expected_shape[1], expected_shape[2]);
    let out = resize.apply(input).unwrap();

    assert_eq!(out.shape(), &expected_shape[..], "Resize output shape");
    assert_close_f64(out.data().unwrap(), &expected_data, 1e-6, "resize_8x8_to_4x4");
}

