#[test]
fn vision_normalize_imagenet_4x4_matches_reference() {
    let ff = load_fixtures();
    let fix = get_fixture(&ff.fixtures, "normalize_imagenet_4x4")
        .expect("fixture normalize_imagenet_4x4 not found");

    let input_data = flatten_nested_f64(&fix["input"]);
    let expected_data = flatten_nested_f64(&fix["expected"]);
    let input_shape: Vec<usize> = fix["input_shape"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_u64().unwrap() as usize)
        .collect();

    let mean: Vec<f64> = fix["params"]["mean"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_f64().unwrap())
        .collect();
    let std: Vec<f64> = fix["params"]["std"]
        .as_array()
        .unwrap()
        .iter()
        .map(|v| v.as_f64().unwrap())
        .collect();

    let norm = VisionNormalize::<f64>::new(
        [mean[0], mean[1], mean[2]],
        [std[0], std[1], std[2]],
    )
    .unwrap();
    let input = make_f64(input_data, input_shape);
    let out = norm.apply(input).unwrap();

    assert_close_f64(out.data().unwrap(), &expected_data, 1e-5, "normalize_imagenet_4x4");
}

