#[test]
fn color_jitter_new_constructor() {
    // Valid params
    let _j = ColorJitter::<f64>::new(0.2, 0.2, 0.2, 0.1).unwrap();
    // Invalid hue (>= 0.5)
    assert!(ColorJitter::<f64>::new(0.0, 0.0, 0.0, 0.5).is_err());
    // Invalid brightness (< 0)
    assert!(ColorJitter::<f64>::new(-0.1, 0.0, 0.0, 0.0).is_err());
}

#[test]
fn color_jitter_output_range_contract() {
    // Output must be clamped to [0.0, 1.0].
    vision_manual_seed(77);
    let data: Vec<f64> = (0..48).map(|i| i as f64 / 48.0).collect();
    let t = make_f64(data, vec![3, 4, 4]);
    let jitter = ColorJitter::<f64>::new(0.5, 0.5, 0.5, 0.2).unwrap();
    let out = jitter.apply(t).unwrap();
    for &v in out.data().unwrap() {
        assert!(
            (0.0..=1.0).contains(&v),
            "ColorJitter output {v} outside [0.0, 1.0]"
        );
    }
}

